<template>
	<view class="card">
		<up-cell-group title="иҪҰдҪҚз”іиҜ·">
			<up-cell title="иҪҰзүҢеҸ·">
				<template #right-icon>
					<input type="text" placeholder="иҜ·иҫ“е…ҘиҪҰзүҢеҸ·" v-model="parkInfo.carNum"/>
				</template>
			</up-cell>
			<up-cell title="е“ҒзүҢ">
				<template #right-icon>
					<input type="text" placeholder="иҜ·иҫ“е…Ҙе“ҒзүҢ" v-model="parkInfo.carBrand"/>
				</template>
			</up-cell>
			<up-cell title="йўңиүІ">
				<template #right-icon>
					<input type="text" placeholder="иҜ·иҫ“е…ҘйўңиүІ" v-model="parkInfo.carColor"/>
				</template>
			</up-cell>
			<up-cell title="иҪҰзүҢеҸ·">
				<template #right-icon>
					<picker mode="selector" :range="types" @change="chiose">
						<view>{{types[typeIndex]}}</view>
					</picker>
				</template>
			</up-cell>
			<up-cell title="еӨҮжіЁ">
				<template #right-icon>
					<input type="text" placeholder="иҜ·иҫ“е…ҘеӨҮжіЁ" v-model="parkInfo.remark"/>
				</template>
			</up-cell>
		</up-cell-group>
	</view>
	<view class="card">
		<button type="primary" @click="submit()">жҸҗдәӨз”іиҜ·</button>
		<button type="default">жҹҘзңӢз”іиҜ·иҝӣеәҰ</button>
	</view>
</template>
<script setup>
import { ref } from 'vue';
import {apiPost} from '../../utils/request.js'
const parkInfo=ref({
	carNum:'',
	carBrand:"",
	carColor:"",
	remark:"",
	carType:"",
	communityId: "2025072783670006",
	ownerId: uni.getStorageSync('personal').memberId,
	state: uni.getStorageSync('personal').ownerTypeCd,
	applyPersonName: uni.getStorageSync('personal').name,
	applyPersonLink: uni.getStorageSync('personal').link,
	applyPersonId: uni.getStorageSync('personal').ownerId,
	userId: uni.getStorageSync('personal').ownerId
})
const typeCode=ref(0)
const typeIndex=ref(0)
const types=["е®¶з”Ёе°ҸжұҪиҪҰ","е®ўиҪҰ","иҙ§иҪҰ"]
const chiose=(e)=>{
	typeIndex.value=e.detail.value
	typeCode.value=typeIndex.value+9001
	parkInfo.value.carType=typeCode.value
}
const submit=async()=>{
	if(!parkInfo.value.carBrand||!parkInfo.value.carNum){
		uni.showToast({
			icon:'none',
			title:"иҜ·е®Ңе–„дҝЎжҒҜ"
		})
		return
	}
	const res=await apiPost("/app/parkingSpaceApply.saveParkingSpaceApply",parkInfo)
	if(res.data.code===0){
		uni.showToast({
			icon:'success',
			title:"иҪҰдҪҚз”іиҜ·жҲҗеҠҹ"
		})
	}
		
	else{
		uni.showToast({
			icon:'error',
			title:"иҪҰдҪҚз”іиҜ·еӨұиҙҘ"
		})
	}
}
</script>

<style scoped lang="scss">
	input{
		text-align: end;
	}   
	button{
		margin: 20rpx;
	}
</style>
